#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 75000
int a[MAXN];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int q;
        scanf("%d", &q);
        int last = 0;
        while (q--) {
            int x, z, c, d;
            scanf("%d %d %d %d", &x, &z, &c, &d);
            x--; z--;
            int k = (c + d * last) % (n - x + 1);
            int y = x + k;
            int t = z + k;
            int map[n + 1];
            memset(map, -1, sizeof(map));
            int flag = 1;
            for (int i = x; i <= y; i++) {
                if (map[a[i]] == -1) {
                    for (int j = z; j <= t; j++) {
                        if (map[a[j]] == -1) {
                            map[a[i]] = a[j];
                            break;
                        }
                    }
                }
                if (map[a[i]] != a[i + (y - x)]) {
                    flag = 0;
                    break;
                }
            }
            if (flag) {
                printf("YES\n");
                last = 1;
            } else {
                printf("NO\n");
                last = 0;
            }
        }
    }
    return 0;
}

