import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            int q = sc.nextInt();
            int last = 0;
            while (q-- > 0) {
                int x = sc.nextInt();
                int z = sc.nextInt();
                int c = sc.nextInt();
                int d = sc.nextInt();
                x--; z--;
                int k = (c + d * last) % (n - x + 1);
                int y = x + k;
                int t = z + k;
                Map<Integer, Integer> map = new HashMap<>();
                boolean flag = true;
                for (int i = x; i <= y; i++) {
                    if (!map.containsKey(a[i])) {
                        for (int j = z; j <= t; j++) {
                            if (!map.containsKey(a[j])) {
                                map.put(a[i], a[j]);
                                break;
                            }
                        }
                    }
                    if (!map.get(a[i]).equals(a[i + (y - x)])) {
                        flag = false;
                        break;
                    }
                }
                if (flag) {
                    System.out.println("YES");
                    last = 1;
                } else {
                    System.out.println("NO");
                    last = 0;
                }
            }
        }
    }
}

